    db.run(`INSERT OR REPLACE INTO universal_photo_captures(capture_id,source_type,file_name,classification,status,request_json,response_json,confidence,created_at,confirmed_at) VALUES (?,?,?,?,?,?,?,?,?,?)`,[captureId,photo?.source||'photo',photo?.name||null,kind,'confirmed',request,JSON.stringify(preview),r.confidence||0,iso,iso]);
