    db.run(`INSERT INTO workflow_events(event_type,intent_type,input_text,status,details_json,created_at,resolved_at) VALUES (?,?,?,?,?,?,?)`,['photo_capture_committed',kind,photo?.name||'Photo','complete',JSON.stringify({request_id:captureId,classification:kind}),iso,iso]);
