function ForwardMealPlanner({tick,targets}){
 const [days,setDays]=useState(7),[expanded,setExpanded]=useState(false),[saved,setSaved]=useState(''),[showShopping,setShowShopping]=useState(false);
 const pantry=query(`SELECT p.pantry_id,p.item,p.food_id,p.quantity,p.unit AS pantry_unit,p.opened,p.expiration,p.priority,p.location,p.status,p.notes,p.on_hand,p.purchase_date,p.verified_at,p.original_servings,f.* FROM pantry p JOIN foods f ON UPPER(f.food_id)=UPPER(p.food_id) WHERE p.on_hand='Yes' AND COALESCE(p.quantity,0)>0 AND COALESCE(f.nutrition_known,0)=1 AND (COALESCE(f.calories,0)>0 OR COALESCE(f.protein,0)>0 OR COALESCE(f.fiber,0)>0)`).map(x=>({...x,type:'food',unit:x.unit||x.pantry_unit,available_servings:Math.max(1,Math.floor(Number(x.quantity)||1)),batch_servings:/roast|batch|chicken|salmon/i.test(x.item||'')?2:1}));
 const recent=query(`SELECT food_id,food_name,eaten_at FROM meals ORDER BY eaten_at DESC LIMIT 30`);
 const restaurants=query(`SELECT planned_local_date,meal_type,food_name,calories,protein,carbs,fiber,fat,saturated_fat,sodium,restaurant_name,source_type,lock_state FROM planned_meals WHERE status='planned' AND source_type='restaurant' AND planned_local_date>=? ORDER BY planned_local_date`,[today()]);
 const weight=query(`SELECT value_primary FROM health_metrics WHERE metric_type='weight' AND value_primary IS NOT NULL ORDER BY measured_at DESC,id DESC LIMIT 1`)[0]?.value_primary||null;
 const result=optimizeMealPlan({candidates:pantry,restaurantEvents:restaurants,recentMeals:recent,days,startDate:new Date(),mealsPerDay:2,targets,currentWeight:weight});
 async function savePlan(){const created=new Date().toISOString(),planId=`plan-${Date.now()}`;await transaction(async db=>{db.run(`INSERT INTO meal_plans(plan_id,name,horizon_days,status,optimization_score,generated_at,committed_at,settings_json,forecast_json,shopping_json) VALUES (?,?,?,?,?,?,?,?,?,?)`,[planId,`${days}-day health plan`,days,'active',result.optimization.score,created,created,JSON.stringify({mealsPerDay:2}),JSON.stringify(result.forecast),JSON.stringify(result.shopping)]);for(const row of result.plan){if(row.source_type==='restaurant')continue;const r=row.candidate||row;db.run(`INSERT INTO planned_meals(planned_at,planned_local_date,meal_type,food_id,food_name,amount,unit,calories,protein,carbs,fiber,fat,saturated_fat,sodium,notes,status,created_at,updated_at,pantry_id,source_type,lock_state,plan_id,batch_group) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,[`${row.date}T12:00:00`,row.date,row.slot||'Meal',r.food_id,row.food_name||r.item||r.name,1,r.unit||'serving',r.calories||row.nutrition?.calories||0,r.protein||row.nutrition?.protein||0,r.carbs||row.nutrition?.carbs||0,r.fiber||row.nutrition?.fiber||0,r.fat||row.nutrition?.fat||0,r.saturated_fat||row.nutrition?.saturated_fat||0,r.sodium||row.nutrition?.sodium||0,JSON.stringify({source:'meal_planning_2',planning_score:row.planningScore,leftover_from:row.leftover_from||null}),'planned',created,created,r.pantry_id||null,row.source_type||'food',row.lock_state||'flexible',planId,row.batch_group||null]);}db.run(`INSERT INTO meal_plan_events(plan_id,event_type,event_date,details_json,created_at) VALUES (?,?,?,?,?)`,[planId,'plan_committed',today(),JSON.stringify(result.summary),created]);});setSaved(`${result.plan.length} meals planned`);setTimeout(()=>setSaved(''),2000)}
 const visible=expanded?result.plan:result.plan.slice(0,10),f=result.forecast;
 return <section className="forward-planner meal-planning-2"><div className="planner-head"><div><span><Clock3/> MEAL PLANNING 2.0</span><h2>Your adaptive health plan</h2><p>Optimized for nutrition, pantry freshness, variety, leftovers, and restaurant commitments.</p></div><div className="planner-horizons">{[1,3,7,14,30].map(n=><button key={n} className={days===n?'active':''} onClick={()=>setDays(n)}>{n===1?'Today':`${n}d`}</button>)}</div></div><div className="plan-score-row"><div className="plan-score"><strong>{result.optimization.score}</strong><span>{result.optimization.label}</span></div><div><b>{result.summary.coveragePercent}% covered</b><small>{result.summary.pantryMeals} pantry · {result.summary.restaurantMeals} restaurant · {result.summary.leftovers} leftovers</small></div></div><div className="planner-summary"><div><strong>{Math.round(f.averages.calories||0)}</strong><span>avg kcal/day</span></div><div><strong>{Math.round(f.averages.protein||0)}g</strong><span>avg protein</span></div><div><strong>{f.pantryUtilization}%</strong><span>pantry use</span></div></div><div className="plan-forecast"><span>30-day weight: <b>{f.weight30??'Learning'}</b></span><span>LDL: <b>{f.ldlDirection}</b></span><span>Confidence: <b>{f.confidence}%</b></span></div>{result.summary.unfilled>0&&<div className="planner-warning"><AlertTriangle/> {result.summary.unfilled} meal slots need groceries or additional choices.</div>}<div className="planner-list">{visible.map((row,i)=><div className="planner-row meal-plan-row" key={`${row.date}-${row.slot}-${i}`}><time>{new Date(`${row.date}T12:00:00`).toLocaleDateString(undefined,{weekday:'short',month:'short',day:'numeric'})}</time><b>{row.food_name||row.candidate?.item||row.candidate?.name}</b><span>{row.slot} · {Math.round(Number(row.nutrition?.calories||row.calories)||0)} kcal · {row.source_type==='leftover'?'leftover':row.source_type==='restaurant'?'restaurant · locked':'flexible'}</span></div>)}</div>{result.plan.length>10&&<button className="show-nutrients" onClick={()=>setExpanded(x=>!x)}>{expanded?'Show first 10':`Show all ${result.plan.length} meals`}</button>}<button className="show-nutrients" onClick={()=>setShowShopping(x=>!x)}><Package/> {showShopping?'Hide':'Show'} smart shopping ({result.shopping.length})</button>{showShopping&&<div className="smart-shopping-plan">{result.shopping.length?result.shopping.map(x=><div key={x.id}><b>{x.name}</b><span>Buy {x.buy} servings · suggested size {x.suggestedSize}</span></div>):<div className="empty">Pantry inventory covers this plan.</div>}</div>}<button className="primary planner-save" disabled={!result.plan.length} onClick={savePlan}><Check/> Commit this plan</button>{saved&&<div className="status">{saved}</div>}</section>
}
function ChefRecommendations({tick,totals,targets,date=today(),onLog}){
 const pref=query('SELECT restaurant_possible FROM daily_preferences WHERE preference_date=?',[date])[0];
 const restaurant=Number(pref?.restaurant_possible)===1;
 const [mode,setMode]=useState(restaurant),[decisionDetail,setDecisionDetail]=useState(null),[foodDetail,setFoodDetail]=useState(null),[revision,setRevision]=useState(0);
 useEffect(()=>setMode(restaurant),[restaurant,tick]);
 async function toggle(next){setMode(next);await run(`INSERT OR REPLACE INTO daily_preferences(preference_date,restaurant_possible,updated_at) VALUES (?,?,?)`,[date,next?1:0,new Date().toISOString()])}
 const remaining={calories:Math.max(0,(targets.calories?.target||1700)-totals.calories),protein:Math.max(0,(targets.protein?.target||0)-totals.protein),fiber:Math.max(0,(targets.fiber?.target||0)-totals.fiber)};
 const pantryCandidates=query(`SELECT p.pantry_id,p.item,p.quantity,p.unit AS pantry_unit,p.opened,p.expiration,p.priority,p.location,recent.last_consumed,f.*
   FROM pantry p JOIN foods f ON UPPER(f.food_id)=UPPER(p.food_id)
   LEFT JOIN (SELECT food_id,MAX(eaten_at) AS last_consumed FROM meals GROUP BY food_id) recent ON UPPER(recent.food_id)=UPPER(f.food_id)
   WHERE p.on_hand='Yes' AND COALESCE(p.quantity,0)>0 AND COALESCE(f.nutrition_known,0)=1
   AND (COALESCE(f.calories,0)>0 OR COALESCE(f.protein,0)>0 OR COALESCE(f.fiber,0)>0)`).map(x=>({...x,type:'food',unit:x.unit||x.pantry_unit}));
 const recipeIds=query(`SELECT COALESCE(NULLIF(recipe_id,''),recipe_name) recipe_id,recipe_name FROM recipes GROUP BY COALESCE(NULLIF(recipe_id,''),recipe_name),recipe_name ORDER BY recipe_name COLLATE NOCASE`);
 const recipeCandidates=recipeIds.map(r=>recipeSnapshot(r.recipe_id)).filter(Boolean).filter(r=>r.nutrition_known===1).map(r=>({type:'recipe',recipe_id:r.recipe_id,item:r.recipe_name,name:r.recipe_name,quantity:1,unit:'recipe',opened:'No',expiration:null,priority:'',location:'Recipe',calories:r.nutrition.calories,protein:r.nutrition.protein,carbs:r.nutrition.carbs,fiber:r.nutrition.fiber,fat:r.nutrition.fat,saturated_fat:r.nutrition.saturated_fat,nutrition_known:1}));
 const scored=evaluateDecision('chef_rank',{candidates:[...pantryCandidates,...recipeCandidates],remaining,daily:totals,targets,restaurantPossible:mode,limit:4});
 return <section className="chef-section"><div className="chef-head"><div><span><ChefHat/> CHEF’S RECOMMENDATIONS</span><h2>{mode?'Restaurant possible':'Home meals only'}</h2></div><div className="restaurant-toggle"><button className={!mode?'active':''} onClick={()=>toggle(false)}>Home</button><button className={mode?'active':''} onClick={()=>toggle(true)}><UtensilsCrossed/> Restaurant</button></div></div>
 <div className="chef-grid">{scored.length?scored.map(({candidate:r,decision},rank)=><article className="chef-card" key={r.pantry_id||`recipe-${r.recipe_id}`}><button type="button" className="chef-score" onClick={()=>setDecisionDetail({title:r.item,decision:{...decision,rank:rank+1}})} aria-label={`Explain score and confidence for ${r.item}`}><strong>{decision.score}</strong><small>{decision.confidence}%<br/>confidence</small><span>Why?</span></button><button type="button" className="chef-food-body" onClick={()=>setFoodDetail(r.type==='recipe'?{type:'recipe',recipe_id:r.recipe_id}:({...r,name:r.name||r.item,pantry_id:r.pantry_id,pantry_quantity:r.quantity,pantry_unit:r.pantry_unit||r.unit}))}><b>{r.item}</b><span>{decision.positive.slice(0,2).join(' · ')||'Best fit from pantry'}</span><em>{Math.round(Number(r.calories)||0)} kcal · {Math.round(Number(r.protein)||0)}g protein{r.type==='recipe'?' · Recipe':''}</em></button></article>):<div className="chef-empty">Import pantry foods or recipes with nutrition to generate recommendations.</div>}</div>
 {decisionDetail&&<DecisionDetails title={decisionDetail.title} decision={decisionDetail.decision} onClose={()=>setDecisionDetail(null)}><section className="decision-block"><h3>Ranking</h3><p>This item ranked #{decisionDetail.decision.rank} among the recommendations evaluated for the current day.</p></section></DecisionDetails>}
 {foodDetail&&<FoodRecipeDetails item={foodDetail} onClose={()=>setFoodDetail(null)} onSaved={()=>setRevision(x=>x+1)}/>}<div className="chef-remaining">Based on approximately {Math.round(remaining.calories)} kcal, {Math.round(remaining.protein)}g protein and {Math.round(remaining.fiber)}g fiber remaining.</div></section>
}
function DailyCommandCenter({summary,actions,onCapture,navigate}){
 const [detail,setDetail]=useState(null),[timelineOpen,setTimelineOpen]=useState(false);
 const timeline=timelineOpen?buildUnifiedTimeline({meals:query('SELECT * FROM meals ORDER BY eaten_at DESC LIMIT 60'),metrics:query('SELECT * FROM health_metrics ORDER BY measured_at DESC LIMIT 60'),pantryEvents:query('SELECT * FROM pantry_events ORDER BY event_at DESC LIMIT 60'),healthEvents:query('SELECT * FROM health_event_timeline ORDER BY event_at DESC LIMIT 60')}):[];
 return <section className="command-center"><div className="command-head"><div><small>DAILY DASHBOARD 2.0</small><h2>{summary.nextAction?.title||'You are caught up'}</h2><p>{summary.nextAction?.why||'No urgent action is waiting.'}</p></div></div><div className="command-grid"><button onClick={()=>summary.nextMeal?setDetail({title:'Next meal',why:`${summary.nextMeal.food_name} is planned next.`,confidence:100,priority:80,type:'meal_plan',engines:['Meal planner'],evidence:[summary.nextMeal.planned_at||'Today']}):(()=>{localStorage.setItem('fizz-open-meal-planner','1');navigate('add')})()}><span>Next meal</span><b>{summary.nextMeal?.food_name||'Not planned'}</b><small>Tap to choose and plan</small></button><button onClick={()=>navigate('pantry')}><span>Pantry attention</span><b>{summary.pantryAttention.length}</b><small>Tap for items</small></button><button onClick={()=>navigate('restaurants')}><span>Dining plans</span><b>{summary.restaurantPlans.length}</b><small>Tap for plans</small></button><button onClick={()=>setDetail({title:'Calories vs plan',why:`You are ${Math.abs(Math.round(summary.variance.calories||0))} calories ${Number(summary.variance.calories||0)>0?'over':'under'} plan.`,confidence:100,priority:70,type:'calories',engines:['Daily nutrition'],evidence:[`${Math.round(summary.variance.calories||0)} kcal variance`]})}><span>Calories vs plan</span><b>{Math.round(summary.variance.calories||0)>0?'+':''}{Math.round(summary.variance.calories||0)}</b><small>Tap for details</small></button></div><div className="action-center"><div className="section-title"><b>Smart Action Center</b><button onClick={()=>setTimelineOpen(x=>!x)}>{timelineOpen?'Actions':'Timeline'}</button></div>{timelineOpen?<div className="playback-list">{timeline.slice(0,20).map(e=><div key={e.id}><time>{new Date(e.eventAt).toLocaleString([],{month:'short',day:'numeric',hour:'numeric',minute:'2-digit'})}</time><b>{e.title}</b><span>{e.detail}</span></div>)}</div>:actions.length?actions.slice(0,4).map(a=><button className="smart-action" key={a.id} onClick={()=>setDetail(a)}><div><b>{a.title}</b><span>{a.why}</span></div><em>{Math.round(a.confidence)}%</em></button>):<div className="empty">Nothing needs immediate attention.</div>}</div>{detail&&<div className="modal-backdrop" onClick={()=>setDetail(null)}><div className="panel explain-panel" onClick={e=>e.stopPropagation()}><div className="edit-head"><h3>{detail.title}</h3><button onClick={()=>setDetail(null)}><X/></button></div>{(()=>{const x=explainRecommendation(detail);return <><p>{x.why}</p><div className="detail-values"><div><span>Confidence</span><b>{x.confidence}%</b></div><div><span>Priority</span><b>{Math.round(detail.priority)}</b></div></div><h4>Contributing engines</h4><p>{x.engines.join(' · ')}</p><h4>Supporting evidence</h4><p>{x.evidence.join(' · ')||'Current recorded state'}</p></>})()}<button className="primary" onClick={()=>{setDetail(null);if(detail.type==='pantry')navigate('pantry');else if(detail.type==='review')navigate('restaurants');else if(detail.type==='preventive')navigate('health');else onCapture()}}>Take action</button></div></div>}</section>
}
function AddMeal({refresh,done,initialFood,clearInitial}){
 const [q,setQ]=useState(''),[selected,setSelected]=useState(null),[amount,setAmount]=useState(''),[selectedUnit,setSelectedUnit]=useState('serving'),[meal,setMeal]=useState('Meal'),[notes,setNotes]=useState(''),[view,setView]=useState(()=>localStorage.getItem('fizz-open-meal-planner')==='1'?'pantry':'all'),[localTick,setLocalTick]=useState(0),[whenMode,setWhenMode]=useState('now'),[pastDateTime,setPastDateTime]=useState(toDateTimeLocal()),[saving,setSaving]=useState(false),[error,setError]=useState(''),[recipeDetail,setRecipeDetail]=useState(null),[quickItem,setQuickItem]=useState(null),[toast,setToast]=useState(''),[showLogOnce,setShowLogOnce]=useState(false),[logOnceError,setLogOnceError]=useState(''),[logOnceSaving,setLogOnceSaving]=useState(false);
 useEffect(()=>{if(localStorage.getItem('fizz-open-meal-planner')==='1')localStorage.removeItem('fizz-open-meal-planner');if(initialFood){setSelected(initialFood);setAmount(String(consumptionServing(initialFood)));setSelectedUnit(initialFood.unit||'serving');setError('');clearInitial?.()}},[initialFood]);
 const search=`%${q}%`; let foods=[],recipes=[];
 if(view==='recipes')recipes=query(`SELECT recipe_id,recipe_name,COUNT(*) ingredient_count FROM recipes WHERE COALESCE(archived,0)=0 AND recipe_name LIKE ? GROUP BY recipe_id,recipe_name ORDER BY recipe_name LIMIT 75`,[search]);
 else if(view==='favorites') foods=query(`SELECT f.* FROM foods f JOIN favorite_foods x ON x.food_id=f.food_id WHERE COALESCE(f.archived,0)=0 AND f.name LIKE ? ORDER BY f.name LIMIT 75`,[search]);
 else if(view==='recent') foods=query(`SELECT f.*, MAX(m.eaten_at) AS last_used FROM foods f JOIN meals m ON m.food_id=f.food_id WHERE COALESCE(f.archived,0)=0 AND f.name LIKE ? GROUP BY f.food_id ORDER BY last_used DESC LIMIT 30`,[search]);
 else if(view==='pantry') foods=query(`SELECT f.*, p.quantity AS pantry_quantity, p.unit AS pantry_unit,p.pantry_id FROM foods f JOIN pantry p ON UPPER(p.food_id)=UPPER(f.food_id) WHERE COALESCE(f.archived,0)=0 AND p.on_hand='Yes' AND f.name LIKE ? GROUP BY f.food_id ORDER BY f.name LIMIT 75`,[search]);
 else foods=query(`SELECT * FROM foods WHERE COALESCE(archived,0)=0 AND name LIKE ? ORDER BY name LIMIT 75`,[search]);
 const favoriteIds=new Set(query('SELECT food_id FROM favorite_foods').map(r=>r.food_id));
 const targets=getTargets(); const todayTotals=query(`SELECT COALESCE(SUM(calories),0) calories,COALESCE(SUM(protein),0) protein,COALESCE(SUM(carbs),0) carbs,COALESCE(SUM(fat),0) fat FROM meals WHERE consumed_local_date=?`,[today()])[0]||{};
 async function toggleFavorite(e,food){e.stopPropagation();if(favoriteIds.has(food.food_id))await run('DELETE FROM favorite_foods WHERE food_id=?',[food.food_id]);else await run('INSERT OR REPLACE INTO favorite_foods(food_id,created_at) VALUES (?,?)',[food.food_id,new Date().toISOString()]);setLocalTick(x=>x+1)}
 function chooseFood(f){setSelected(f);setAmount(String(consumptionServing(f)));setSelectedUnit(f.unit||'serving');setError('')}
 async function archiveFood(f){if(!confirm(`Archive ${f.name}?\n\nIt will be removed from future food selections. Historical meal records will remain unchanged, including nutrition snapshots. You can restore it later from Settings → Archived Items.`))return;await transaction(async db=>{db.run('UPDATE foods SET archived=1,archived_at=? WHERE food_id=?',[new Date().toISOString(),f.food_id]);db.run('DELETE FROM favorite_foods WHERE food_id=?',[f.food_id])});if(selected?.food_id===f.food_id)setSelected(null);setToast(`${f.name} archived. History preserved.`);setLocalTick(x=>x+1);setTimeout(()=>setToast(''),2200)}
 async function archiveRecipe(r){if(!confirm(`Archive ${r.recipe_name}?\n\nIt will be removed from future recipe selections. Historical meals will remain unchanged. You can restore it later from Settings → Archived Items.`))return;await run('UPDATE recipes SET archived=1,archived_at=? WHERE recipe_id=? OR recipe_name=?',[new Date().toISOString(),r.recipe_id,r.recipe_name]);setToast(`${r.recipe_name} archived. History preserved.`);setLocalTick(x=>x+1);setTimeout(()=>setToast(''),2200)}
 function calculated(){if(!selected)return {known:false};const baseAmount=convertAmount(amount,selectedUnit,selected.unit);if(baseAmount==null)return {known:false,conversionError:true};return {...nutritionFor(selected,baseAmount,selected.unit),baseAmount}}
 async function save(asPlan=false){
  setError('');if(!selected||!Number(amount)||Number(amount)<=0){setError('Enter a quantity greater than zero.');return}const calc=calculated();if(calc.conversionError){setError(`Cannot safely convert ${selectedUnit} to ${selected.unit}. Choose a compatible unit.`);return}
  const consumed=whenMode==='now'?new Date():new Date(pastDateTime);if(Number.isNaN(consumed.getTime())){setError('Choose a valid date and time.');return}if(!asPlan&&consumed.getTime()>Date.now()+60000){setError('Consumption time cannot be in the future.');return}
  const n=calc;setSaving(true);try{if(asPlan){await transaction(async db=>{db.run(`INSERT INTO planned_meals(planned_at,planned_local_date,meal_type,food_id,food_name,amount,unit,calories,protein,carbs,fiber,fat,saturated_fat,notes,status,created_at,updated_at,pantry_id,source_type) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,[consumed.toISOString(),localDateKey(consumed),meal,selected.food_id,selected.name,Number(amount),selectedUnit,n.calories,n.protein,n.carbs,n.fiber,n.fat,n.saturated_fat,notes,'planned',new Date().toISOString(),new Date().toISOString(),selected.pantry_id||null,selected.pantry_id?'pantry':'food'])});localStorage.setItem('fizz-meal-added','1');refresh();done();return}
   const duplicate=query(`SELECT id FROM meals WHERE food_id=? AND amount=? AND unit=? AND ABS(strftime('%s',eaten_at)-strftime('%s',?))<=20 LIMIT 1`,[selected.food_id,Number(amount),selectedUnit,consumed.toISOString()])[0];if(duplicate&&!confirm('This looks like a duplicate tap. Log it again?'))return;
   await transaction(async db=>{let pantryDelta=0,pantryOpenedChanged=0;if(selected.pantry_id){const current=Number(selected.pantry_quantity)||0,inventoryUnit=selected.pantry_unit||selected.unit;const converted=convertAmount(amount,selectedUnit,inventoryUnit);if(converted!=null){pantryDelta=converted;if(pantryDelta>current&&!confirm(`Only ${current} ${inventoryUnit} remain. Log anyway?`))throw new Error('Meal logging cancelled.');db.run('UPDATE pantry SET quantity=COALESCE(quantity,0)-? WHERE pantry_id=?',[pantryDelta,selected.pantry_id])}else if(isPackageUnit(inventoryUnit)){const pantryRow=db.query('SELECT opened FROM pantry WHERE pantry_id=? LIMIT 1',[selected.pantry_id])[0];pantryOpenedChanged=pantryRow?.opened==='Yes'?0:1;db.run("UPDATE pantry SET opened='Yes' WHERE pantry_id=?",[selected.pantry_id])}}
    db.run(`INSERT INTO meals(eaten_at,created_at,updated_at,consumed_local_date,timezone_offset_minutes,meal_type,food_id,food_name,amount,unit,calories,protein,carbs,fiber,fat,saturated_fat,notes,nutrition_known,pantry_id,pantry_delta,pantry_opened_changed) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,[consumed.toISOString(),new Date().toISOString(),new Date().toISOString(),localDateKey(consumed),-consumed.getTimezoneOffset(),meal,selected.food_id,selected.name,Number(amount),selectedUnit,n.calories,n.protein,n.carbs,n.fiber,n.fat,n.saturated_fat,notes,n.known?1:0,selected.pantry_id||null,pantryDelta,pantryOpenedChanged])});localStorage.setItem('fizz-meal-added','1');refresh();done()
  }catch(err){setError(err instanceof Error?err.message:String(err))}finally{setSaving(false)}}
 async function saveLogOnce(event){
  event.preventDefault();setLogOnceError('');const form=new FormData(event.currentTarget),name=String(form.get('name')||'').trim(),qty=Number(form.get('amount')),unit=String(form.get('unit')||'serving').trim()||'serving',mealType=String(form.get('meal_type')||'Meal'),note=String(form.get('notes')||'').trim(),mode=String(form.get('when_mode')||'now'),dateValue=String(form.get('past_datetime')||'');
  if(!name){setLogOnceError('Enter a food or meal name.');return}if(!qty||qty<=0){setLogOnceError('Enter a quantity greater than zero.');return}
  const consumed=mode==='past'?new Date(dateValue):new Date();if(Number.isNaN(consumed.getTime())){setLogOnceError('Choose a valid date and time.');return}if(consumed.getTime()>Date.now()+60000){setLogOnceError('Consumption time cannot be in the future.');return}
  const nutrient=name=>{const raw=String(form.get(name)||'').trim();return raw===''?null:Number(raw)};const nutrition={calories:nutrient('calories'),protein:nutrient('protein'),carbs:nutrient('carbs'),fat:nutrient('fat'),fiber:nutrient('fiber'),saturated_fat:nutrient('saturated_fat')};
  if(Object.values(nutrition).some(value=>value!=null&&(!Number.isFinite(value)||value<0))){setLogOnceError('Nutrition values must be zero or greater.');return}
  const known=Object.values(nutrition).some(value=>value!=null),created=new Date().toISOString(),sourceRecordId=`one-time-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;setLogOnceSaving(true);
  try{await run(`INSERT INTO meals(eaten_at,created_at,updated_at,consumed_local_date,timezone_offset_minutes,meal_type,food_id,food_name,amount,unit,calories,protein,carbs,fiber,fat,saturated_fat,notes,nutrition_known,source,source_record_id) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,[consumed.toISOString(),created,created,localDateKey(consumed),-consumed.getTimezoneOffset(),mealType,null,name,qty,unit,nutrition.calories,nutrition.protein,nutrition.carbs,nutrition.fiber,nutrition.fat,nutrition.saturated_fat,note,known?1:0,'one_time',sourceRecordId]);localStorage.setItem('fizz-meal-added','1');setShowLogOnce(false);setToast(`${name} logged once.`);refresh();setLocalTick(x=>x+1);setTimeout(()=>setToast(''),2200)}catch(err){setLogOnceError(err instanceof Error?err.message:String(err))}finally{setLogOnceSaving(false)}
 }
 const n=calculated();
 return <><header className="add-header"><small>MEAL LOG</small><h1>{view==='pantry'?'Choose a meal to plan':'Add food'}</h1>{view==='pantry'&&<p>Select a pantry food, choose quantity and time, then tap <b>Plan meal</b>.</p>}</header>
 <button type="button" className="log-once-launch" onClick={()=>{setLogOnceError('');setShowLogOnce(true)}}><Plus/><div><b>Log Once</b><span>Record a food or meal without saving it to Foods, Recipes, or Pantry</span></div><ChevronRight/></button>
 <div className="discovery-tabs">{[['all','All'],['recent','Recent'],['favorites','Favorites'],['pantry','Pantry'],['recipes','Recipes']].map(([id,label])=><button key={id} className={view===id?'active':''} onClick={()=>{setView(id);setSelected(null)}}>{id==='recent'&&<Clock3/>}{id==='favorites'&&<Star/>}{id==='pantry'&&<Box/>}{id==='recipes'&&<ChefHat/>}<span>{label}</span></button>)}</div>
 <label className="search"><Search/><input value={q} onChange={e=>setQ(e.target.value)} placeholder={`Search ${view==='all'?'foods':view}…`}/></label>
 <div className="list foods">{view==='recipes'?(recipes.length?recipes.map(r=><SwipeArchiveCard key={r.recipe_id||r.recipe_name} label={r.recipe_name} onOpen={()=>setRecipeDetail({type:'recipe',recipe_id:r.recipe_id})} onArchive={()=>archiveRecipe(r)} onQuickLog={()=>setQuickItem({type:'recipe',item:r})}><div className="item select"><div><b>{r.recipe_name}</b><span>{r.ingredient_count} ingredients</span></div><em>Recipe</em></div></SwipeArchiveCard>):<div className="empty">No recipes found.</div>):(foods.length?foods.map(f=><SwipeArchiveCard key={f.food_id} label={f.name} onOpen={()=>chooseFood(f)} onArchive={()=>archiveFood(f)} onQuickLog={()=>setQuickItem({type:'food',item:f})}><div className={'item select '+(selected?.food_id===f.food_id?'chosen':'')}><div><b>{f.name}</b><span>{f.category} · {f.default_serving} {f.unit}{view==='pantry'&&f.pantry_quantity!=null?` · ${f.pantry_quantity} ${f.pantry_unit||''} on hand`:''}</span></div><div className="food-actions"><em>{Number(f.nutrition_known)===1?`${Math.round(Number(f.calories)||0)} kcal`:'Needs nutrition'}</em><button type="button" aria-label={favoriteIds.has(f.food_id)?'Remove from favorites':'Add to favorites'} className={'favorite '+(favoriteIds.has(f.food_id)?'on':'')} onPointerDown={e=>e.stopPropagation()} onClick={e=>toggleFavorite(e,f)}><Star fill={favoriteIds.has(f.food_id)?'currentColor':'none'}/></button></div></div></SwipeArchiveCard>):<div className="empty">No {view==='all'?'foods':view} found.</div>)}</div>
 {selected&&<div className="modal-backdrop entry-modal" onClick={()=>setSelected(null)}><div className="panel meal-entry fixed-editor" onClick={e=>e.stopPropagation()}><div className="edit-head sticky-head"><h3>{selected.name}</h3><button type="button" aria-label="Close food editor" onClick={()=>setSelected(null)}><X/></button></div><div className="editor-scroll"><label>Meal type<select value={meal} onChange={e=>setMeal(e.target.value)}><option>Breakfast</option><option>Lunch</option><option>Dinner</option><option>Snack</option><option>Meal</option></select></label><label>Quantity<div className="amount unit-amount"><input autoFocus type="number" inputMode="decimal" min="0" step="0.1" value={amount} onChange={e=>setAmount(e.target.value)}/><select aria-label="Serving unit" value={selectedUnit} onChange={e=>setSelectedUnit(e.target.value)}>{unitOptions(selected.unit).map(u=><option key={u} value={u}>{u}</option>)}</select></div></label><div className="nutrition-preview">{n.conversionError?<><b>Unit conversion unavailable</b><span>Choose a compatible unit.</span></>:n.known?<><b>{Math.round(n.calories)} kcal</b><span>{Math.round(n.protein)}g protein · {Math.round(n.carbs)}g carbs · {Math.round(n.fat)}g fat · {Math.round(n.fiber)}g fiber · {Math.round((n.saturated_fat||0)*10)/10}g sat fat</span><div className="macro-impact"><small>Projected today</small><span>Calories {Math.round(finite(todayTotals.calories)+n.calories)} / {Math.round(targets.calories?.target||0)}</span><span>Protein {Math.round(finite(todayTotals.protein)+n.protein)} / {Math.round(targets.protein?.target||0)}g</span><span>Carbs {Math.round(finite(todayTotals.carbs)+n.carbs)} / {Math.round(targets.carbs?.target||0)}g</span><span>Fat {Math.round(finite(todayTotals.fat)+n.fat)} / {Math.round(targets.fat?.target||0)}g</span></div></>:<><b>Needs nutrition</b><span>This food has no verified nutrition profile yet.</span></>}</div><fieldset className="when-picker"><legend>Consumed</legend><label className={whenMode==='now'?'selected':''}><input type="radio" name="when" checked={whenMode==='now'} onChange={()=>setWhenMode('now')}/><div><b>Now</b><span>Use the current device date and time</span></div></label><label className={whenMode==='past'?'selected':''}><input type="radio" name="when" checked={whenMode==='past'} onChange={()=>setWhenMode('past')}/><div><b>Past date and time</b><span>Log something consumed earlier</span></div></label>{whenMode==='past'&&<input className="datetime" type="datetime-local" value={pastDateTime} max={toDateTimeLocal()} onChange={e=>setPastDateTime(e.target.value)}/>}</fieldset><label>Notes<input value={notes} onChange={e=>setNotes(e.target.value)} placeholder="Optional"/></label>{error&&<div className="inline-error">{error}</div>}</div><div className="editor-actions"><button className="secondary" disabled={saving} onClick={()=>save(true)}>Plan meal</button><button className="primary" disabled={saving} onClick={()=>save(false)}>{saving?'Saving…':'Log food'}</button></div></div></div>}
 {showLogOnce&&<div className="modal-backdrop entry-modal" onClick={()=>setShowLogOnce(false)}><form className="panel meal-entry fixed-editor log-once-editor" onSubmit={saveLogOnce} onClick={e=>e.stopPropagation()}><div className="edit-head sticky-head"><div><small>FH-1259 · ONE-TIME FOOD</small><h3>Log Once</h3></div><button type="button" aria-label="Close Log Once editor" onClick={()=>setShowLogOnce(false)}><X/></button></div><div className="editor-scroll"><label>Food or meal name<input name="name" autoFocus required placeholder="Example: Birthday cake"/></label><div className="amount unit-amount"><label>Quantity<input name="amount" type="number" inputMode="decimal" min="0.1" step="0.1" defaultValue="1" required/></label><label>Unit<input name="unit" defaultValue="serving" required/></label></div><label>Meal type<select name="meal_type" defaultValue="Meal"><option>Breakfast</option><option>Lunch</option><option>Dinner</option><option>Snack</option><option>Meal</option></select></label><fieldset className="log-once-nutrition"><legend>Nutrition for this logged amount</legend><div className="nutrition-form-grid"><label>Calories<input name="calories" type="number" inputMode="decimal" min="0" step="0.1" placeholder="Unknown"/></label><label>Protein (g)<input name="protein" type="number" inputMode="decimal" min="0" step="0.1" placeholder="Unknown"/></label><label>Carbs (g)<input name="carbs" type="number" inputMode="decimal" min="0" step="0.1" placeholder="Unknown"/></label><label>Fat (g)<input name="fat" type="number" inputMode="decimal" min="0" step="0.1" placeholder="Unknown"/></label><label>Fiber (g)<input name="fiber" type="number" inputMode="decimal" min="0" step="0.1" placeholder="Unknown"/></label><label>Saturated fat (g)<input name="saturated_fat" type="number" inputMode="decimal" min="0" step="0.1" placeholder="Unknown"/></label></div><small>Blank means unknown. Zero means the value is known to be zero.</small></fieldset><fieldset className="when-picker"><legend>Consumed</legend><label className="selected"><input type="radio" name="when_mode" value="now" defaultChecked/><div><b>Now</b><span>Use the current device date and time</span></div></label><label><input type="radio" name="when_mode" value="past"/><div><b>Past date and time</b><span>Enter the time below</span></div></label><input className="datetime" name="past_datetime" type="datetime-local" defaultValue={toDateTimeLocal()} max={toDateTimeLocal()}/></fieldset><label>Notes<textarea name="notes" placeholder="Optional context, preparation, or source"/></label><section className="log-once-boundary"><b>Logged only to your history</b><span>This will not create a Food Database item, Recipe, or Pantry record.</span></section>{logOnceError&&<div className="inline-error">{logOnceError}</div>}</div><div className="editor-actions"><button type="button" className="secondary" disabled={logOnceSaving} onClick={()=>setShowLogOnce(false)}>Cancel</button><button className="primary" disabled={logOnceSaving}>{logOnceSaving?'Saving…':'Log Once'}</button></div></form></div>}
 {recipeDetail&&<FoodRecipeDetails item={recipeDetail} onClose={()=>setRecipeDetail(null)} onSaved={()=>{refresh();setLocalTick(x=>x+1)}}/>}{quickItem&&<div className="modal-backdrop" onClick={()=>setQuickItem(null)}><div className="panel quick-log-sheet" onClick={e=>e.stopPropagation()}><div className="edit-head"><div><small>QUICK LOG</small><h3>{quickItem.item.name||quickItem.item.recipe_name}</h3></div><button aria-label="Cancel quick log" onClick={()=>setQuickItem(null)}><X/></button></div><p>How would you like to use this {quickItem.type}?</p><button className="action" onClick={()=>{if(quickItem.type==='food'){chooseFood(quickItem.item);setQuickItem(null)}else{setRecipeDetail({type:'recipe',recipe_id:quickItem.item.recipe_id});setQuickItem(null)}}}><Clock3/><div><b>Add as proposed meal</b><span>Open the item and plan it for later</span></div></button><button className="action" onClick={()=>{if(quickItem.type==='food'){chooseFood(quickItem.item);setQuickItem(null)}else{setRecipeDetail({type:'recipe',recipe_id:quickItem.item.recipe_id});setQuickItem(null)}}}><Check/><div><b>Add as consumed meal</b><span>Open the item and log it now</span></div></button><button className="secondary" onClick={()=>setQuickItem(null)}>Cancel</button></div></div>}{toast&&<div className="success-toast">{toast}</div>}</>
}

function Pantry({onLogFood,tick}){
 const [q,setQ]=useState(''),[view,setView]=useState('recommend'),[localTick,setLocalTick]=useState(0),[currentLocation,setCurrentLocation]=useState('Home'),[showScore,setShowScore]=useState(false),[showManual,setShowManual]=useState(false);
 const allRows=query(`SELECT p.*,f.default_serving,f.calories,f.protein,f.fiber,f.saturated_fat,f.sodium,f.category AS food_category,(SELECT COALESCE(SUM(m.amount),0) FROM meals m WHERE m.pantry_id=p.pantry_id AND COALESCE(m.pantry_opened_changed,0)=1) AS package_consumed,(SELECT m.unit FROM meals m WHERE m.pantry_id=p.pantry_id AND COALESCE(m.pantry_opened_changed,0)=1 ORDER BY m.id DESC LIMIT 1) AS consumption_unit FROM pantry p LEFT JOIN foods f ON UPPER(f.food_id)=UPPER(p.food_id) ORDER BY CASE WHEN p.on_hand='Yes' THEN 0 ELSE 1 END,p.item LIMIT 1000`);
 const events=query('SELECT * FROM pantry_events ORDER BY event_at DESC LIMIT 1000');
 const planned=query("SELECT * FROM planned_meals WHERE status='planned' ORDER BY planned_at LIMIT 250");
 const history=query("SELECT pantry_id,food_id,amount AS quantity,eaten_at AS event_at FROM meals WHERE pantry_id IS NOT NULL ORDER BY eaten_at DESC LIMIT 1000");
 const locations=query("SELECT * FROM pantry_locations WHERE active=1 ORDER BY sort_order,name");
 const rows=filterPantryInventory(allRows,{search:q,location:currentLocation,locations});
 const intel=buildPantryIntelligence({items:rows.map(r=>({...r,category:r.category||r.food_category})),events,plannedMeals:planned,history,currentLocation});
 const empty=pantryEmptyState({allItems:allRows,filteredItems:rows,search:q,location:currentLocation});
 async function verify(r){const now=new Date().toISOString();await transaction(db=>{db.run("UPDATE pantry SET verified_at=?,quantity_accuracy='verified',on_hand=CASE WHEN COALESCE(quantity,0)>0 THEN 'Yes' ELSE on_hand END WHERE pantry_id=?",[now,r.pantry_id]);db.run("INSERT INTO pantry_events(pantry_id,event_type,quantity,unit,notes,event_at) VALUES (?,?,?,?,?,?)",[r.pantry_id,'verify',r.quantity,r.unit,'Verified from Pantry Intelligence',now])});setLocalTick(x=>x+1)}
 async function setLocation(name){setCurrentLocation(name);await run("UPDATE pantry_locations SET is_current=CASE WHEN name=? THEN 1 ELSE 0 END,updated_at=?",[name,new Date().toISOString()])}
 async function saveManual(e){e.preventDefault();const f=new FormData(e.currentTarget),name=String(f.get('name')||'').trim();if(!name)return;const id=`manual-${Date.now()}`,iso=new Date().toISOString(),foodId=`food-${Date.now()}`;await transaction(db=>{db.run('INSERT INTO foods(food_id,name,category,default_serving,unit,nutrition_known,notes) VALUES (?,?,?,?,?,?,?)',[foodId,name,f.get('category')||'Food',Number(f.get('serving'))||1,f.get('unit')||'item',0,'Manual pantry creation']);db.run('INSERT INTO pantry(pantry_id,item,food_id,brand,on_hand,quantity,unit,location,status,purchase_date,expiration,notes,verified_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)',[id,name,foodId,f.get('brand')||null,'Yes',Number(f.get('quantity'))||1,f.get('unit')||'item',f.get('location')||currentLocation,'Active',f.get('purchase_date')||null,f.get('expiration')||null,f.get('notes')||null,iso])});setShowManual(false);setLocalTick(x=>x+1)}
 const score=intel.health,verified=intel.items.filter(i=>i.confidence>=75).length,lower=intel.items.filter(i=>i.waste.score>=55).slice(0,3),improve=intel.items.filter(i=>i.opportunity.score>=55).slice(0,3);
 return <><header className="pantry-summary-header" onClick={()=>document.getElementById('pantry-inventory')?.scrollIntoView({behavior:'smooth'})}><small>PANTRY INTELLIGENCE 2.0</small><h1>What should I eat?</h1><p>{rows.length} matching items · {currentLocation} · Tap to view inventory</p></header>
 <button className="pantry-health-card tappable" onClick={()=>setShowScore(true)}><div className="pantry-score"><strong>{score.score}</strong><span>Pantry Health Score</span></div><div><h2>{score.label}</h2><p>Freshness, nutrition, variety, waste risk, and inventory confidence.</p><small>Tap for details</small></div></button>
 <div className="pantry-toolbar"><label className="location-picker">Current location<select value={currentLocation} onChange={e=>setLocation(e.target.value)}>{locations.length?locations.map(l=><option key={l.location_id}>{l.name}</option>):<option>Home</option>}</select></label><button className="primary" onClick={()=>setShowManual(true)}><Plus/> Add food</button></div>
 <div className="pantry-intel-tabs">{[['recommend','Eat next'],['waste','Waste risk'],['restock','Restock'],['shopping','Shopping']].map(([id,label])=><button key={id} className={view===id?'active':''} onClick={()=>setView(id)}>{label}</button>)}</div>
 {view==='recommend'&&<section className="pantry-intel-list"><h2>Chef’s Recommendations</h2>{intel.recommendations.length?intel.recommendations.map((r,i)=><article key={r.id||r.pantry_id}><b>#{i+1}</b><div><strong>{r.item}</strong><span>{r.opportunity.label} · Expected Health Gain {r.opportunity.healthGain}</span><small>{r.freshness.quality} · {Math.round(r.remainingServings*10)/10} servings · {r.verificationState}</small></div><button onClick={()=>{const food=resolvePantryFood(r);if(food)onLogFood({...food,pantry_id:r.pantry_id,pantry_quantity:r.quantity,pantry_unit:r.unit})}}>Eat</button></article>):<div className="empty"><b>{empty?.title||'No qualifying recommendation is available.'}</b><span>{empty?.action||'Add quantity or nutrition details to improve recommendations.'}</span></div>}</section>}
 {view==='waste'&&<section className="pantry-intel-list"><h2>Waste prevention</h2>{intel.wasteRisks.map(r=><article key={r.id||r.pantry_id}><AlertTriangle/><div><strong>{r.item}</strong><span>{r.waste.reasons.join(' · ')||'Recommended this week'}</span><small>{r.freshness.safety} · Risk {r.waste.score}%</small></div></article>)}{!intel.wasteRisks.length&&<div className="empty">No foods currently at elevated waste risk.</div>}</section>}
 {view==='restock'&&<section className="pantry-intel-list"><h2>Smart restock</h2>{intel.restock.map(r=><article key={r.id||r.pantry_id}><Clock3/><div><strong>{r.item}</strong><span>{r.forecast.daysRemaining} days remaining</span><small>{r.forecast.remainingAfterPlan} servings after planned meals</small></div></article>)}{!intel.restock.length&&<div className="empty">Nothing is projected to run out this week.</div>}</section>}
 <label className="search pantry-search"><Search/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Search pantry…"/></label>
 {view==='shopping'&&<section className="pantry-intel-list"><h2>Optimized shopping list</h2>{intel.shopping.map(r=><article key={r.id}><Package/><div><strong>{r.item}</strong><span>Buy {r.buy} {r.unit}</span><small>{r.reason}</small></div></article>)}{!intel.shopping.length&&<div className="empty">Current inventory covers planned demand.</div>}</section>}
 <div className="list" id="pantry-inventory">{intel.items.map(r=><div className="item pantry-item pantry-smart-item" key={r.id||r.pantry_id}><button type="button" className="pantry-open" onClick={()=>{const food=resolvePantryFood(r);if(food)onLogFood({...food,pantry_id:r.pantry_id,pantry_quantity:r.quantity,pantry_unit:r.unit})}}><div><b>{r.item}</b><span>{r.brand}{r.location?' · '+r.location:''}{r.opened==='Yes'?' · Open':''} · {r.freshness.quality}</span></div><em>{r.quantity??''} {r.unit}</em></button><button className="verify-chip" onClick={()=>verify(r)}>{r.confidence>=75?<Check/>:<ShieldCheck/>}{r.confidence}%</button></div>)}</div>
 {showScore&&<div className="decision-page" role="dialog" aria-modal="true"><div className="decision-page-inner"><header className="decision-detail-head"><div><small>PANTRY INTELLIGENCE</small><h2>Pantry Health Score</h2></div><button onClick={()=>setShowScore(false)} aria-label="Close"><X/></button></header><section className="pantry-score-detail"><strong>{score.score}</strong><h3>{score.label}</h3><p>Calculated from the exact inventory currently displayed for {currentLocation}{q?` matching “${q}”`:''}.</p></section><div className="pantry-component-grid">{Object.entries(score.components).map(([k,v])=><section key={k}><small>{k.replaceAll('_',' ')}</small><b>{v}</b><p>{k==='freshness'?'Higher when foods are within recorded freshness windows.':k==='waste'?'Higher when fewer foods are at risk of spoilage.':k==='confidence'?'Based on verification recency and quantity quality.':`Contribution from ${k} across displayed foods.`}</p></section>)}</div><section className="decision-block"><h3>Inventory evidence</h3><p>{verified} verified items · {intel.items.length} displayed items · calculated {new Date().toLocaleString()}</p>{improve.length>0&&<p><b>Improving:</b> {improve.map(i=>i.item).join(', ')}</p>}{lower.length>0&&<p><b>Needs attention:</b> {lower.map(i=>i.item).join(', ')}</p>}</section><button className="primary" onClick={()=>setShowScore(false)}>Back to Pantry</button></div></div>}
 {showManual&&<div className="modal-backdrop" onClick={()=>setShowManual(false)}><form className="panel fixed-editor pantry-manual-editor" onSubmit={saveManual} onClick={e=>e.stopPropagation()}><div className="edit-head sticky-head"><div><small>PANTRY</small><h3>Add food manually</h3></div><button type="button" onClick={()=>setShowManual(false)}><X/></button></div><div className="editor-scroll"><label>Food name<input name="name" autoFocus required/></label><label>Brand<input name="brand"/></label><label>Category<input name="category"/></label><div className="amount"><label>Quantity<input name="quantity" type="number" inputMode="decimal" step="0.1" defaultValue="1"/></label><label>Unit<input name="unit" defaultValue="item"/></label></div><label>Storage location<select name="location" defaultValue={currentLocation}>{locations.map(l=><option key={l.location_id}>{l.name}</option>)}</select></label><label>Purchase date<input name="purchase_date" type="date"/></label><label>Expiration / best-by<input name="expiration" type="date"/></label><label>Notes<textarea name="notes"/></label></div><div className="editor-actions"><button type="button" className="secondary" onClick={()=>setShowManual(false)}>Cancel</button><button className="primary"><Check/> Save to Pantry</button></div></form></div>}</>}

function NutritionEditor({food,onClose,onSaved}){
 const fields=[['calories','Calories'],['protein','Protein (g)'],['carbs','Carbs (g)'],['fat','Fat (g)'],['fiber','Fiber (g)'],['saturated_fat','Saturated fat (g)']];
 const initialReviewed=Object.fromEntries(fields.map(([k])=>[k,food[k]!=null]));
 const [form,setForm]=useState({calories:food.calories??'',protein:food.protein??'',carbs:food.carbs??'',fat:food.fat??'',fiber:food.fiber??'',saturated_fat:food.saturated_fat??'',default_serving:food.default_serving??1,unit:food.unit||'serving'}),[reviewed,setReviewed]=useState(initialReviewed),[error,setError]=useState('');
 const set=(k,v)=>{setForm(f=>({...f,[k]:v}));setReviewed(r=>({...r,[k]:v!==''}))};
 const markNA=k=>{setForm(f=>({...f,[k]:'0'}));setReviewed(r=>({...r,[k]:true}))};
 async function save(){const serving=Number(form.default_serving);if(!serving||serving<=0){setError('Enter a valid serving size.');return}const missing=fields.filter(([k])=>!reviewed[k]);if(missing.length){setError(`Review every field. Enter a value or tap N/A for: ${missing.map(([,l])=>l).join(', ')}`);return}const vals=fields.map(([k])=>Number(form[k])||0);
  await transaction(async db=>{db.run(`UPDATE foods SET calories=?,protein=?,carbs=?,fat=?,fiber=?,saturated_fat=?,default_serving=?,unit=?,nutrition_known=1,notes=TRIM(COALESCE(notes,'') || ' | Nutrition source: manual; all fields reviewed') WHERE food_id=?`,[...vals,serving,form.unit,food.food_id]);db.run(`UPDATE meals SET calories=?*amount/?,protein=?*amount/?,carbs=?*amount/?,fat=?*amount/?,fiber=?*amount/?,saturated_fat=?*amount/?,nutrition_known=1,updated_at=? WHERE UPPER(food_id)=UPPER(?)`,[vals[0],serving,vals[1],serving,vals[2],serving,vals[3],serving,vals[4],serving,vals[5],serving,new Date().toISOString(),food.food_id])});onSaved()}
 return <div className="modal-backdrop nutrition-modal"><div className="panel nutrition-editor"><div className="edit-head sticky-head"><h3>{food.name}</h3><button onClick={onClose}><X/></button></div><div className="nutrition-scroll"><div className="nutrition-form-grid">{fields.map(([k,l])=><label key={k}>{l}<div className="review-field"><input type="number" inputMode="decimal" min="0" step="0.1" value={form[k]} placeholder={reviewed[k]?'0':'Unknown'} onChange={e=>set(k,e.target.value)}/><button type="button" className={reviewed[k]&&String(form[k])==='0'?'na active':'na'} onClick={()=>markNA(k)}>N/A</button></div></label>)}</div><label>Serving size<div className="amount"><input type="number" min="0.1" step="0.1" value={form.default_serving} onChange={e=>set('default_serving',e.target.value)}/><input value={form.unit} onChange={e=>set('unit',e.target.value)}/></div></label>{error&&<div className="inline-error">{error}</div>}<small className="editor-note">Blank means unknown. A numeric value or N/A means the field was reviewed.</small></div><div className="editor-actions"><button className="secondary" onClick={onClose}>Cancel</button><button className="primary" onClick={save}><Check/> Save nutrition</button></div></div></div>
}

const EXCHANGE_VERSION=1;
function exchangeInstructions(requestType){return {
 recipient:'AI assistant with access to attached product, nutrition-label, menu, barcode, or meal photos',
 purpose:requestType,
 rules:[
  'Return ONLY one valid JSON object. Do not add markdown, commentary, or code fences.',
  'Preserve format, schema_version, request_type, request_id, and existing non-null verified values.',
  'Populate only fields supported by visible evidence. Never invent a value.',
  'Use null when information is not visible or cannot be determined reliably. Use numeric 0 only when the source explicitly shows zero.',
  'Keep all field names exactly as supplied. Field order does not matter.',
  'Use grams for macronutrients, milligrams for sodium/cholesterol, and calories as kcal.',
  'Include confidence from 0 to 1 and short evidence notes for populated records.'
 ]
}}
function productExchange(food={}){return {format:'fizz-health-exchange',schema_version:EXCHANGE_VERSION,request_type:'product_enrichment',request_id:`product-${food.food_id||'new'}-${Date.now()}`,instructions:exchangeInstructions('Enrich this food/product record from the attached package, UPC, ingredients, and Nutrition Facts photos.'),record:{food_id:food.food_id||null,product:{name:food.name||null,brand:food.brand||null,category:food.category||null,upc:null},serving:{amount:food.default_serving??null,unit:food.unit||null,description:null,servings_per_container:null},nutrition:{calories:food.calories??null,protein_g:food.protein??null,carbohydrate_g:food.carbs??null,fiber_g:food.fiber??null,total_fat_g:food.fat??null,saturated_fat_g:food.saturated_fat??null,sodium_mg:food.sodium??null,potassium_mg:food.potassium??null,total_sugars_g:null,added_sugars_g:null,cholesterol_mg:null},ingredients:null,allergens:[],notes:food.notes||null},response_requirements:{return_full_record:true,unknown_value:null,do_not_overwrite_non_null_verified_values:true}}}
