 const totals=query(`SELECT COALESCE(SUM(calories),0) calories,COALESCE(SUM(protein),0) protein,COALESCE(SUM(fiber),0) fiber,COALESCE(SUM(saturated_fat),0) saturated_fat FROM meals WHERE consumed_local_date=?`,[today()])[0]||{};
 const ranked=selected?rankRestaurantMenu({meals,totals,targets:getTargets(),limit:20}):[];
 const profile=selected?restaurantProfileSummary({restaurant:selected,visits,meals}):null;
 async function plan(meal){const now=new Date();await run(`INSERT INTO planned_meals(planned_at,planned_local_date,meal_type,food_name,amount,unit,calories,protein,carbs,fiber,fat,saturated_fat,notes,status,created_at,updated_at,source_type,restaurant_name,restaurant_meal_id,menu_price) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,[now.toISOString(),today(),'Dinner',meal.meal_name,1,'serving',meal.calories||0,meal.protein||0,meal.carbs||0,meal.fiber||0,meal.fat||0,meal.saturated_fat||0,meal.notes||'','planned',now.toISOString(),now.toISOString(),'restaurant',selected.name,meal.id,meal.price??null]);refresh();done()}
