function AboutPage({onBack}){const db=databaseStatus(),[history,setHistory]=useState(false),latest=RELEASE_HISTORY[0];return <PageShell eyebrow="ABOUT" title="Fizz Health" description="Version, diagnostics, and release history." onBack={onBack}><section className="about-summary"><div><span>Version</span><b>{latest.version}</b></div><div><span>Build</span><b>{latest.build}</b></div><div><span>Created</span><b>{new Date(latest.created).toLocaleString([],{dateStyle:'medium',timeStyle:'short'})}</b></div><div><span>Schema</span><b>v{db.schemaVersion}</b></div><div><span>Release ID</span><b>{latest.releaseId}</b></div><div><span>Storage</span><b>Local SQLite</b></div></section><section className="release-notes-panel"><small>WHAT’S NEW IN v{latest.version}</small><h2>{latest.name}</h2><div className="release-scroll">{latest.stories.map(([id,title])=><div key={id}><b>{id}</b><span>{title}</span></div>)}</div><p className="testing-note"><ShieldCheck/> Use this list as the testing checklist for the current build.</p></section><button className="action" onClick={()=>setHistory(true)}><BookOpen/><div><b>View full release history</b><span>Browse every release with FH/HF numbers and timestamps</span></div><ChevronRight/></button>{history&&<div className="decision-page" role="dialog" aria-modal="true"><div className="decision-page-inner"><header className="decision-detail-head"><div><small>RELEASE HISTORY</small><h2>All releases</h2></div><button onClick={()=>setHistory(false)} aria-label="Close release history"><X/></button></header><div className="release-history">{RELEASE_HISTORY.map((r,i)=><details key={r.releaseId} open={i===0}><summary><div><b>v{r.version} · {r.name}</b><span>{new Date(r.created).toLocaleString([],{dateStyle:'medium',timeStyle:'short'})} · {r.type}</span></div><ChevronDown/></summary><div className="release-history-body"><p><b>Build:</b> {r.build} · <b>Release ID:</b> {r.releaseId}</p>{r.stories.map(([id,title])=><div className="history-story" key={id}><b>{id}</b><span>{title}</span></div>)}<p><b>Known issues:</b> {r.knownIssues.length?r.knownIssues.join('; '):'None recorded.'}</p></div></details>)}</div></div></div>}</PageShell>}
function DatabaseTransferPage({onBack,refresh}){const [status,setStatus]=useState(''),[busy,setBusy]=useState(false),workbookInput=useRef(null);async function workbook(file){if(!file)return;setBusy(true);setStatus(`Importing ${file.name}…`);try{const r=await importWorkbook(file);setStatus(`Imported ${r.foods} foods, ${r.pantry} pantry items, ${r.recipes} recipe ingredients, ${r.healthMetrics||0} health readings, ${r.labs||0} lab results, and ${r.workoutSets||0} workout sets. ${r.coverage?.length||0} workbook sheets audited.`);refresh()}catch(e){setStatus(`Import failed: ${e.message||e}`)}finally{setBusy(false)}}async function sqlite(e){const f=e.target.files?.[0];if(!f)return;setBusy(true);try{await importDatabase(await f.arrayBuffer());setStatus('Database restored and migrated successfully.');refresh()}catch(err){setStatus(`Restore failed: ${err.message||err}`)}finally{setBusy(false);e.target.value=''}}function exportDb(){const blob=new Blob([exportDatabase()],{type:'application/vnd.sqlite3'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`FizzHealth-${today()}.sqlite`;a.click();URL.revokeObjectURL(a.href)}return <PageShell eyebrow="DATA" title="Database import & export" description="Move user data without changing the database schema." onBack={onBack}>{status&&<div className="import-banner working">{status}</div>}<section className="data-section"><input ref={workbookInput} className="visually-hidden" type="file" accept=".xlsx" onChange={e=>workbook(e.target.files?.[0])}/><button className="action" disabled={busy} onClick={()=>workbookInput.current?.click()}><Upload/><div><b>Import Fizz Health workbook</b><span>Foods, pantry, recipes, health data, and history</span></div></button><button className="action" onClick={exportDb}><Download/><div><b>Export SQLite backup</b><span>Save a complete portable database</span></div></button><label className="action"><Upload/><div><b>Restore SQLite backup</b><span>Restore and migrate a previous backup</span></div><input type="file" accept=".sqlite,.db" onChange={sqlite}/></label></section></PageShell>}
function SchemaPage({onBack}){const [status,setStatus]=useState(''),input=useRef(null),db=databaseStatus();const schema=()=>({format:'fizz-health-schema',schema_version:db.schemaVersion,exported_at:new Date().toISOString(),tables:query("SELECT name,sql FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' ORDER BY name")});function exportSchema(){downloadJson(`FizzHealth-schema-v${db.schemaVersion}.json`,schema())}async function importSchema(file){if(!file)return;try{const data=JSON.parse(await file.text());if(data.format!=='fizz-health-schema'||!Array.isArray(data.tables))throw new Error('Not a valid Fizz Health schema JSON file.');setStatus(`Schema JSON validated: version ${data.schema_version}, ${data.tables.length} tables. No user data was changed.`)}catch(e){setStatus(`Validation failed: ${e.message||e}`)}}return <PageShell eyebrow="SCHEMA" title="Schema JSON management" description="Database structure is managed separately from user data." onBack={onBack}>{status&&<div className="import-banner working">{status}</div>}<section className="data-section"><button className="action" onClick={exportSchema}><FileJson/><div><b>Export schema JSON</b><span>Save table definitions and schema version</span></div></button><input ref={input} className="visually-hidden" type="file" accept="application/json,.json" onChange={e=>importSchema(e.target.files?.[0])}/><button className="action" onClick={()=>input.current?.click()}><Upload/><div><b>Import and validate schema JSON</b><span>Validate structure before any migration work</span></div></button><section className="schema-view"><h2>Current schema</h2><div className="release-scroll">{schema().tables.map(t=><details key={t.name}><summary>{t.name}</summary><pre>{t.sql}</pre></details>)}</div></section></section></PageShell>}
function ArchivedItemsPage({onBack,refresh}){const [kind,setKind]=useState('foods'),[q,setQ]=useState(''),[tick,setTick]=useState(0),search=`%${q}%`,foods=query('SELECT * FROM foods WHERE COALESCE(archived,0)=1 AND name LIKE ? ORDER BY archived_at DESC,name',[search]),recipes=query('SELECT recipe_id,recipe_name,MAX(archived_at) archived_at,COUNT(*) ingredient_count FROM recipes WHERE COALESCE(archived,0)=1 AND recipe_name LIKE ? GROUP BY recipe_id,recipe_name ORDER BY archived_at DESC',[search]);async function restoreFood(f){await run('UPDATE foods SET archived=0,archived_at=NULL WHERE food_id=?',[f.food_id]);setTick(x=>x+1);refresh()}async function restoreRecipe(r){await run('UPDATE recipes SET archived=0,archived_at=NULL WHERE recipe_id=? OR recipe_name=?',[r.recipe_id,r.recipe_name]);setTick(x=>x+1);refresh()}const rows=kind==='foods'?foods:recipes;return <PageShell eyebrow="ARCHIVE" title="Archived items" description="Restore foods and recipes without changing historical meals." onBack={onBack}><div className="filter-pills"><button className={kind==='foods'?'active':''} onClick={()=>setKind('foods')}>Foods</button><button className={kind==='recipes'?'active':''} onClick={()=>setKind('recipes')}>Recipes</button></div><label className="search"><Search/><input value={q} onChange={e=>setQ(e.target.value)} placeholder={`Search archived ${kind}…`}/></label><div className="list">{rows.map(r=><div className="item" key={r.food_id||r.recipe_id||r.recipe_name}><div><b>{r.name||r.recipe_name}</b><span>Archived {r.archived_at?new Date(r.archived_at).toLocaleString():'date unknown'}{r.ingredient_count?` · ${r.ingredient_count} ingredients`:''}</span></div><button className="restore-button" onClick={()=>kind==='foods'?restoreFood(r):restoreRecipe(r)}><RotateCcw/> Restore</button></div>)}{!rows.length&&<div className="empty">No archived {kind}.</div>}</div></PageShell>}
function MaintenancePage({onBack,refresh}){const [status,setStatus]=useState(''),db=databaseStatus();async function wipe(){if(confirm('Erase all local Fizz Health data on this device? This cannot be undone.')){await resetDatabase();setStatus('Local database erased and rebuilt.');refresh()}}return <PageShell eyebrow="MAINTENANCE" title="Maintenance & audit" description="Diagnostics and recovery tools for the local database." onBack={onBack}><section className="about-summary"><div><span>Schema</span><b>v{db.schemaVersion}</b></div><div><span>Foods</span><b>{db.foods}</b></div><div><span>Pantry</span><b>{db.pantry}</b></div><div><span>Recipes</span><b>{db.recipes}</b></div><div><span>Nutrition coverage</span><b>{db.nutritionCoverage}%</b></div><div><span>Historical meals</span><b>{db.history?.total_meals||0}</b></div></section>{status&&<div className="import-banner success">{status}</div>}<section className="data-section"><button className="action" onClick={()=>setStatus(`Audit complete: ${db.foodsMissingNutrition} foods missing nutrition; ${db.pantryNutritionIssues?.length||0} pantry link issues.`)}><ShieldCheck/><div><b>Run database audit</b><span>Check nutrition coverage and pantry mappings</span></div></button><button className="action danger" onClick={wipe}><Trash2/><div><b>Erase local database</b><span>Use only after exporting a backup</span></div></button></section></PageShell>}
function Data({refresh}){const [page,setPage]=useState(null);if(page==='about')return <AboutPage onBack={()=>setPage(null)}/>;if(page==='database')return <DatabaseTransferPage onBack={()=>setPage(null)} refresh={refresh}/>;if(page==='schema')return <SchemaPage onBack={()=>setPage(null)}/>;if(page==='profile')return <PersonalHealthProfile onBack={()=>setPage(null)} onClose={()=>setPage(null)}/>;if(page==='nutrients')return <NutrientConfiguration onBack={()=>setPage(null)} onClose={()=>setPage(null)}/>;if(page==='archived')return <ArchivedItemsPage onBack={()=>setPage(null)} refresh={refresh}/>;if(page==='maintenance')return <MaintenancePage onBack={()=>setPage(null)} refresh={refresh}/>;const panels=[['about',Info,'About & release notes','Version, build timestamp, diagnostics, current notes, and full history'],['database',Database,'Database import & export','Backup, restore, and workbook data transfer'],['schema',FileJson,'Schema JSON','View, export, import, and validate database structure'],['profile',UserRound,'Personal health profile','Identity-neutral health inputs, activity, smoking, and goals'],['nutrients',SlidersHorizontal,'Preferences & nutrient targets','Targets, limits, formulas, units, and dashboard behavior'],['archived',Archive,'Archived items','Restore archived foods and recipes'],['maintenance',Wrench,'Maintenance & audit','Database diagnostics, integrity checks, and reset tools']];return <><header><Brand/><small>SETTINGS</small><h1>Settings</h1><p>Choose a focused area. Tasks are grouped by purpose and kept off this hub.</p></header><section className="settings-grid">{panels.map(([id,Icon,title,desc])=><button key={id} onClick={()=>setPage(id)}><Icon/><div><b>{title}</b><span>{desc}</span></div><ChevronRight/></button>)}</section></>}

createRoot(document.getElementById('root')).render(<App/>);
